// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect, useRef, useCallback } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'
import { Calendar, QrCode, Trash2, Check } from 'lucide-react'
import DatePicker from 'react-datepicker'
import { subDays } from 'date-fns'
import Etiqueta from './Etiqueta'
import { QRCodeSVG as QRCode } from 'qrcode.react'

export default function TelaEsterilizacao() {
  // estado do passo atual
  const [step, setStep] = useState(1)
  // operação escolhida: 'entrada' ou 'saida'
  const [operation, setOperation] = useState(null)

  // estados originais
  const [codigo, setCodigo] = useState('')
  const [allCaixas, setAllCaixas] = useState([])
  const [caixas, setCaixas] = useState([])
  const [alunoPin, setAlunoPin] = useState('')
  const [alunoNome, setAlunoNome] = useState('')
  const [pinValidated, setPinValidated] = useState(false)
  const [historico, setHistorico] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [filterDate, setFilterDate] = useState('')
  const [printData, setPrintData] = useState(null)
  const [printCheckbox, setPrintCheckbox] = useState(false)
  const [printedBoxes, setPrintedBoxes] = useState([])
  const datePickerRef = useRef(null)
  const componentRef = useRef(null)
  const storedUser = JSON.parse(localStorage.getItem('user') || '{}')
  const usuarioLogadoNome = storedUser.nome || ''

  const BADGE_STYLES = [
    'bg-blue-100 text-blue-800',
    'bg-green-100 text-green-800',
    'bg-yellow-100 text-yellow-800',
    'bg-purple-100 text-purple-800',
  ]

  // --- efeitos originais ---
  useEffect(() => {
    if (!printData) return
    const area = document.getElementById('area-impressao')
    if (!area) return
    const html = `
      <html>
        <head>
          <title>Impressão de Etiqueta</title>
          <style>body{margin:0;padding:8mm;font-family:sans-serif;}</style>
        </head>
        <body>${area.innerHTML}</body>
      </html>`
    const w = window.open('', '_blank', 'width=600,height=400')
    w.document.write(html)
    w.document.close()
    w.focus()
    w.print()
    setPrintData(null)
    setTimeout(() => w.close(), 500)
  }, [printData])

  useEffect(() => {
    axios.get('/api/caixas')
      .then(res => setAllCaixas(res.data))
      .catch(() => setAllCaixas([]))
  }, [])

  const fetchHistory = useCallback(() => {
    if (!pinValidated || !alunoNome) return
    axios.get('/api/movimentacoes')
      .then(res => {
        const hoje = new Date()
        const from = subDays(hoje, 30).toISOString().slice(0, 10)
        const to = hoje.toISOString().slice(0, 10)
        const fil = res.data.filter(m => {
          const dia = new Date(m.criado_em).toISOString().slice(0, 10)
          return m.alunoNome === alunoNome && dia >= from && dia <= to
        })
        setHistorico(fil)
      })
      .catch(() => setHistorico([]))
  }, [alunoNome, pinValidated])

  useEffect(() => { fetchHistory() }, [fetchHistory])

  // --- funções originais ---
  const suggestions = codigo
    ? allCaixas
        .filter(c =>
          c.nome.toLowerCase().includes(codigo.toLowerCase()) ||
          c.codigo_barras.includes(codigo)
        )
        .slice(0, 5)
    : []

  const addCaixa = c => {
    setCaixas(prev => [...prev, c])
    toast.success(`Caixa adicionada: ${c.nome}`, { autoClose: 5000 })
    setCodigo('')
  }

  const buscarCaixa = () => {
    const encontrada = allCaixas.find(c =>
      c.codigo_barras === codigo ||
      c.nome.toLowerCase().includes(codigo.toLowerCase())
    )
    if (!encontrada) {
      toast.error('Caixa não encontrada pelo código ou nome.', { autoClose: 5000 })
      return
    }
    addCaixa(encontrada)
  }

  const validarPin = () => {
    if (alunoPin.trim().length !== 4) {
      toast.warn('PIN deve ter 4 dígitos.', { autoClose: 5000 })
      return
    }
    axios.get(`/api/alunos/pin/${alunoPin}`)
      .then(res => {
        setAlunoNome(res.data.nome)
        setPinValidated(true)
        toast.success(`PIN validado: ${res.data.nome}`, { autoClose: 5000 })
        fetchHistory()
      })
      .catch(() => {
        toast.error('Aluno não encontrado por este PIN.', { autoClose: 5000 })
      })
  }

  const handlePrint = caixaEntry => {
    setPrintData({
      alunoNome,
      caixaId: caixaEntry.id,
      caixaNome: caixaEntry.nome,
      criadoEm: caixaEntry.criado_em || new Date().toISOString(),
      recebidoPor: usuarioLogadoNome,
    })
    setPrintedBoxes(pb => [...pb, caixaEntry.id])
  }

  const operar = async tipo => {
    if (!pinValidated) {
      toast.warn('Valide o PIN antes.', { autoClose: 5000 })
      return
    }
    if (caixas.length === 0) {
      toast.warn('Adicione ao menos uma caixa.', { autoClose: 5000 })
      return
    }
    if (tipo === 'saida') {
      const invalid = caixas.filter(c => {
        const hist = historico.filter(m => m.caixa_id === c.id)
        return hist.length === 0 || hist[0].tipo !== 'entrada'
      })
      if (invalid.length) {
        invalid.forEach(c =>
          toast.error(`Não é possível dar saída da caixa "${c.nome}" sem entrada.`, { autoClose: 5000 })
        )
        return
      }
    }
    try {
      await Promise.all(caixas.map(c =>
        axios.post(`/api/movimentacoes/${tipo}`, {
          caixa_id: c.id,
          aluno_pin: alunoPin
        })
      ))
      toast.success(`${tipo === 'entrada' ? 'Entrada' : 'Saída'} registrada para ${alunoNome}!`, { autoClose: 5000 })
    } catch {
      toast.error(`Erro ao registrar ${tipo}.`, { autoClose: 5000 })
    }
  }

  const removerCaixa = id => {
    setCaixas(prev => prev.filter(c => c.id !== id))
  }

  const handleDeleteHistory = async id => {
    if (!window.confirm('Deseja realmente excluir esta movimentação?')) return
    try {
      await axios.delete(`/api/movimentacoes/${id}`)
      setHistorico(prev => prev.filter(m => m.id !== id))
      toast.success('Movimentação excluída.', { autoClose: 5000 })
    } catch {
      toast.error('Erro ao excluir movimentação.', { autoClose: 5000 })
    }
  }

  const handleEditHistory = async m => {
    const novoTipo = window.prompt('Novo tipo ("entrada" ou "saida"):', m.tipo)
    if (!novoTipo || !['entrada','saida'].includes(novoTipo)) {
      toast.error('Tipo inválido.', { autoClose: 5000 })
      return
    }
    try {
      await axios.put(`/api/movimentacoes/${m.id}`, { tipo: novoTipo, aluno_id: m.aluno_id })
      setHistorico(prev => prev.map(x => x.id===m.id?{...x,tipo:novoTipo}:x))
      toast.success('Movimentação atualizada.', { autoClose: 5000 })
    } catch {
      toast.error('Erro ao atualizar movimentação.', { autoClose: 5000 })
    }
  }

  const caixaCounts = caixas.reduce((acc,c)=>{
    acc[c.id]?acc[c.id].qty++:acc[c.id]={...c,qty:1}
    return acc
  },{})
  const uniqueCaixas = Object.values(caixaCounts)

  const stockByBox = {}
  historico.forEach(m=>{
    stockByBox[m.caixaNome]=(stockByBox[m.caixaNome]||0)+(m.tipo==='entrada'?1:-1)
  })

  // --- fluxos por passo ---
  return (
    <div className="max-w-4xl mx-auto py-10 px-4 space-y-6">
      <h2 className="text-2xl font-bold">Controle de Esterilização</h2>

      {step === 1 && (
        <div className="flex gap-4">
          <button
            onClick={()=>{ setOperation('entrada'); setStep(2) }}
            className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-full"
          >Entrada</button>
          <button
            onClick={()=>{ setOperation('saida'); setStep(2) }}
            className="bg-red-600 hover:bg-red-700 text-white px-6 py-3 rounded-full"
          >Saída</button>
        </div>
      )}

      {step === 2 && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <h3 className="text-lg font-semibold">Informe seu PIN</h3>
          <input
            type="password"
            placeholder="PIN do aluno"
            value={alunoPin}
            onChange={e=>setAlunoPin(e.target.value.replace(/\D/g,'').slice(0,4))}
            onKeyDown={e=>e.key==='Enter' && validarPin()}
            className="w-full border rounded px-3 py-2"
          />
          <button
            onClick={validarPin}
            className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full"
          >Validar PIN</button>
          {pinValidated && (
            <div>
              <p>Aluno: <span className="font-semibold">{alunoNome}</span></p>
              <button
                onClick={()=>setStep(3)}
                className="mt-4 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-full"
              >Avançar</button>
            </div>
          )}
        </div>
      )}

      {step === 3 && pinValidated && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <h3 className="font-semibold">Informe os materiais ({operation})</h3>
          <div className="flex gap-2">
            <input
              type="text"
              placeholder="Código ou nome da caixa"
              value={codigo}
              onChange={e=>setCodigo(e.target.value)}
              onKeyDown={e=>e.key==='Enter'&&buscarCaixa()}
              className="flex-1 border rounded px-3 py-2"
            />
            <button
              onClick={buscarCaixa}
              className="bg-[#1A1C2C] text-white px-4 py-2 rounded-full"
            >Adicionar</button>
          </div>
          <div className="flex flex-wrap gap-2">
            {uniqueCaixas.map(c=>(
              <div key={c.id} className="bg-gray-100 px-3 py-1 rounded-full flex items-center">
                {c.nome} ({c.qty})
                <button onClick={()=>removerCaixa(c.id)} className="ml-2">×</button>
              </div>
            ))}
          </div>
          <label className="flex items-center gap-2">
            <input
              type="checkbox"
              checked={printCheckbox}
              onChange={e=>setPrintCheckbox(e.target.checked)}
            />
            Imprimir etiquetas
          </label>
          <button
            onClick={()=>{
              operar(operation)
              if(printCheckbox) setStep(4)
              else {
                // volta ao início
                setStep(1)
                setOperation(null)
              }
            }}
            className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-full"
          >
            {printCheckbox?'Próximo':'Confirmar'}
          </button>
        </div>
      )}

      {step === 4 && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <h3 className="font-semibold">Impressão de etiquetas</h3>
          <div className="space-y-2">
            {uniqueCaixas.map(c=>(
              <div key={c.id} className="flex items-center gap-4">
                <span>{c.nome}</span>
                <button
                  onClick={()=>handlePrint(c)}
                  className="flex items-center gap-1"
                >
                  <QrCode size={18} />
                  {printedBoxes.includes(c.id) && <Check size={16} className="text-green-600"/>}
                </button>
              </div>
            ))}
          </div>
          <div className="flex gap-4 mt-4">
            <button
              onClick={()=>{
                uniqueCaixas.forEach(c=>!printedBoxes.includes(c.id)&&handlePrint(c))
              }}
              className="bg-green-600 hover:bg-green-700 text-white px-6 py-2 rounded-full"
            >Imprimir todos</button>
            <button
              onClick={()=>{
                // finaliza e reseta
                setStep(1)
                setOperation(null)
                setCaixas([])
                setAlunoPin('')
                setPinValidated(false)
                setHistorico([])
                setSearchTerm('')
                setFilterDate('')
                setPrintCheckbox(false)
                setPrintedBoxes([])
              }}
              className="bg-gray-600 hover:bg-gray-700 text-white px-6 py-2 rounded-full"
            >
              Finalizar
            </button>
          </div>
        </div>
      )}

      {/* bloco de impressão oculto */}
      {printData && (
        <div id="area-impressao" style={{position:'absolute',left:-10000,top:-10000}}>
          <div className="font-bold mb-2">{printData.caixaNome}</div>
          <Etiqueta
            ref={componentRef}
            alunoNome={printData.alunoNome}
            caixaId={printData.caixaId}
            criadoEm={printData.criadoEm}
            recebidoPor={printData.recebidoPor}
          />
        </div>
      )}
    </div>
  )
}
